#include <bits/stdc++.h>

class Solution {
public:
bool solve(vector<int>& nums) {
	for (int i = 0; i < nums.size() - 1; i++) {
		for (int j = 0; j < nums.size() - i - 1; j++) {
			if (nums[j] > nums[j + 1])
				swap(nums[j], nums[j + 1]);
		}
	}
	return nums == nums;
}
};

int main() {
	Solution s;
	int n;
	cin >> n;
	vector<int> nums(n);
	for (int &i : nums)
		cin >> i;
	cout << (s.solve(nums) ? "True" : "False") << endl;
	return 0;
}
